import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Nav = () => {
  const { user, logout } = useAuth();
  
  // Add this to see if user is detected
  console.log('Current user:', user);

  return (
    <nav>
      <div style={{ background: '#333', padding: '10px', color: 'white' }}>
        <Link to="/" style={{ color: 'white', marginRight: '10px' }}>Home</Link>
        <Link to="/about" style={{ color: 'white', marginRight: '10px' }}>About</Link>
        <Link to="/contact" style={{ color: 'white', marginRight: '10px' }}>Contact</Link>
        
        {user ? (
          <>
            <Link to="/profile" style={{ color: 'white', marginRight: '10px' }}>Profile</Link>
            <Link to="/create-post" style={{ color: 'white', marginRight: '10px' }}>New Post</Link>
            {user.role === 'admin' && (
              <Link to="/admin" style={{ color: 'white', marginRight: '10px' }}>Admin</Link>
            )}
            <button onClick={logout} style={{ marginLeft: 'auto' }}>Logout ({user.name})</button>
          </>
        ) : (
          <>
            <Link to="/login" style={{ color: 'white', marginRight: '10px', marginLeft: 'auto' }}>Login</Link>
            <Link to="/register" style={{ color: 'white', marginRight: '10px' }}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
};

export default Nav;
